import { useEffect, useState, useRef } from 'react';
import Layout from '../components/Layout';
import { adminAPI } from '../api';

export default function AdminBolgeYonetim() {
  const mapRef = useRef(null);
  const leafletMap = useRef(null);
  const drawnItems = useRef(null);
  const [bolgeler, setBolgeler] = useState([]);
  const [mudurler, setMudurler] = useState([]);
  const [loading, setLoading] = useState(true);
  const [cizimMod, setCizimMod] = useState(false);
  const [cizilen, setCizilen] = useState(null);
  const [form, setForm] = useState({ ad: '', aciklama: '', mudur_id: '' });
  const [modalOpen, setModalOpen] = useState(false);
  const [editBolge, setEditBolge] = useState(null);
  const [msg, setMsg] = useState(null);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    setLoading(true);
    try {
      const [bR, uR] = await Promise.all([
        adminAPI.getBolgeler(),
        adminAPI.getKullanicilar()
      ]);
      setBolgeler(bR.data);
      setMudurler(uR.data.filter(u => u.role === 'bolge_mudur' && u.aktif));
    } catch {}
    setLoading(false);
  };

  useEffect(() => {
    if (leafletMap.current) return;
    const L = window.L;
    if (!L) return;

    leafletMap.current = L.map(mapRef.current, { center: [39.0, 35.0], zoom: 6 });
    L.tileLayer('https://{s}.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png', {
      attribution: '©OpenStreetMap ©CARTO'
    }).addTo(leafletMap.current);

    drawnItems.current = new L.FeatureGroup().addTo(leafletMap.current);

    const drawControl = new L.Control.Draw({
      draw: {
        polygon: { shapeOptions: { color: '#f97316', fillOpacity: 0.2 } },
        rectangle: { shapeOptions: { color: '#f97316', fillOpacity: 0.2 } },
        circle: false, circlemarker: false, marker: false, polyline: false
      },
      edit: { featureGroup: drawnItems.current }
    });
    leafletMap.current.addControl(drawControl);

    leafletMap.current.on(L.Draw.Event.CREATED, (e) => {
      drawnItems.current.clearLayers();
      drawnItems.current.addLayer(e.layer);
      const coords = e.layer.getLatLngs()[0].map(p => [p.lat, p.lng]);
      setCizilen(coords);
      setModalOpen(true);
    });
  }, []);

  // Mevcut bölgeleri haritada göster
  useEffect(() => {
    if (!leafletMap.current || !window.L) return;
    const L = window.L;

    // Mevcut bölge layerlerini temizle (sadece drawn items değil, custom olanlar)
    leafletMap.current.eachLayer(layer => {
      if (layer._bolgeLayer) leafletMap.current.removeLayer(layer);
    });

    bolgeler.forEach(b => {
      const latlngs = b.koordinatlar.map(c => [c[0], c[1]]);
      const polygon = L.polygon(latlngs, {
        color: '#3b82f6', fillColor: '#3b82f6', fillOpacity: 0.15, weight: 2
      }).addTo(leafletMap.current);
      polygon._bolgeLayer = true;
      polygon.bindTooltip(`<strong>${b.ad}</strong><br>${b.merkez_sayisi} merkez`, { permanent: false });
    });
  }, [bolgeler]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!cizilen && !editBolge) { setMsg({ type: 'danger', text: 'Haritada bölge çizin!' }); return; }
    setSaving(true); setMsg(null);
    try {
      const payload = {
        ad: form.ad,
        aciklama: form.aciklama,
        koordinatlar: cizilen || editBolge?.koordinatlar,
        mudur_id: form.mudur_id ? Number(form.mudur_id) : null,
      };
      if (editBolge) {
        await adminAPI.updateBolge(editBolge.id, payload);
        setMsg({ type: 'success', text: 'Bölge güncellendi!' });
      } else {
        await adminAPI.createBolge(payload);
        setMsg({ type: 'success', text: 'Bölge oluşturuldu!' });
      }
      fetchData();
      setTimeout(() => { setModalOpen(false); setForm({ ad: '', aciklama: '', mudur_id: '' }); setCizilen(null); setEditBolge(null); setMsg(null); }, 1200);
    } catch (err) {
      setMsg({ type: 'danger', text: err.response?.data?.detail || 'Hata oluştu' });
    }
    setSaving(false);
  };

  const handleDelete = async (id) => {
    if (!window.confirm('Bölgeyi silmek istediğinizden emin misiniz?')) return;
    try { await adminAPI.deleteBolge(id); fetchData(); } catch {}
  };

  const handleEdit = (b) => {
    setEditBolge(b);
    setForm({ ad: b.ad, aciklama: b.aciklama || '', mudur_id: b.mudur_id || '' });
    setCizilen(b.koordinatlar);
    setModalOpen(true);
  };

  return (
    <Layout title="Bölge Yönetimi">
      {/* Harita */}
      <div className="card" style={{ marginBottom: 20 }}>
        <div className="card-header">
          <div className="card-title">🗺️ Haritadan Bölge Çiz</div>
          <div style={{ fontSize: 12, color: 'var(--text3)' }}>
            Sol panelden ✏️ (poligon) veya ◻️ (dikdörtgen) aracını seç, haritada bölge çiz
          </div>
        </div>
        <div ref={mapRef} style={{ height: 450, borderRadius: 8 }} />
      </div>

      {/* Bölge Listesi */}
      <div className="card">
        <div className="card-header">
          <div className="card-title">Tanımlı Bölgeler ({bolgeler.length})</div>
          <button className="btn btn-primary btn-sm" onClick={() => { setEditBolge(null); setForm({ ad: '', aciklama: '', mudur_id: '' }); setCizilen(null); setModalOpen(true); }}>
            + Manuel Ekle
          </button>
        </div>
        {loading ? <div className="loading"><div className="spinner" /></div> : (
          bolgeler.length === 0 ? (
            <div className="empty-state">
              <div className="empty-icon">🗺️</div>
              <div className="empty-text">Henüz bölge tanımlanmadı. Haritadan çizerek başlayın!</div>
            </div>
          ) : (
            <div className="table-wrapper">
              <table>
                <thead>
                  <tr><th>Bölge Adı</th><th>Açıklama</th><th>Bölge Müdürü</th><th>Merkez Sayısı</th><th>Koordinat Sayısı</th><th>İşlem</th></tr>
                </thead>
                <tbody>
                  {bolgeler.map(b => (
                    <tr key={b.id}>
                      <td><strong>{b.ad}</strong></td>
                      <td style={{ fontSize: 12, color: 'var(--text2)' }}>{b.aciklama || '—'}</td>
                      <td>
                        {b.mudur_adi
                          ? <span style={{ color: 'var(--accent3)', fontSize: 12 }}>{b.mudur_adi}</span>
                          : <span style={{ color: 'var(--text3)', fontSize: 12 }}>Atanmadı</span>}
                      </td>
                      <td>
                        <span className="badge badge-info">{b.merkez_sayisi} merkez</span>
                      </td>
                      <td style={{ fontSize: 12, fontFamily: 'IBM Plex Mono', color: 'var(--text3)' }}>
                        {b.koordinatlar?.length} nokta
                      </td>
                      <td>
                        <div style={{ display: 'flex', gap: 6 }}>
                          <button className="btn btn-secondary btn-sm" onClick={() => handleEdit(b)}>✏️</button>
                          <button className="btn btn-danger btn-sm" onClick={() => handleDelete(b.id)}>🗑</button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )
        )}
      </div>

      {/* Modal */}
      {modalOpen && (
        <div className="modal-overlay" onClick={e => e.target === e.currentTarget && setModalOpen(false)}>
          <div className="modal" style={{ maxWidth: 500 }}>
            <div className="modal-header">
              <div className="modal-title">{editBolge ? 'Bölgeyi Düzenle' : 'Yeni Bölge Tanımla'}</div>
              <button className="modal-close" onClick={() => setModalOpen(false)}>✕</button>
            </div>
            {msg && <div className={`alert alert-${msg.type}`}>{msg.text}</div>}

            {cizilen && (
              <div style={{ background: 'rgba(34,197,94,0.1)', border: '1px solid var(--accent3)', borderRadius: 6, padding: '8px 12px', marginBottom: 12, fontSize: 12, color: 'var(--accent3)' }}>
                ✓ {cizilen.length} koordinatlı bölge çizildi
              </div>
            )}
            {!cizilen && !editBolge && (
              <div style={{ background: 'rgba(249,115,22,0.1)', border: '1px solid var(--accent)', borderRadius: 6, padding: '8px 12px', marginBottom: 12, fontSize: 12, color: 'var(--accent)' }}>
                ⚠️ Önce haritadan bir bölge çizin, veya koordinatları düzenlemek için kaydedin.
              </div>
            )}

            <form onSubmit={handleSubmit}>
              <div className="form-group">
                <label className="form-label">Bölge Adı *</label>
                <input className="form-control" value={form.ad} onChange={e => setForm(f => ({...f, ad: e.target.value}))} required placeholder="Örn: Deprem Bölgesi, Ege Sahil Bölgesi" />
              </div>
              <div className="form-group">
                <label className="form-label">Açıklama</label>
                <input className="form-control" value={form.aciklama} onChange={e => setForm(f => ({...f, aciklama: e.target.value}))} placeholder="Opsiyonel açıklama" />
              </div>
              <div className="form-group">
                <label className="form-label">Bölge Müdürü</label>
                <select className="form-control" value={form.mudur_id} onChange={e => setForm(f => ({...f, mudur_id: e.target.value}))}>
                  <option value="">— Seçin (opsiyonel) —</option>
                  {mudurler.map(u => (
                    <option key={u.id} value={u.id}>{u.ad} {u.soyad} — {u.email}</option>
                  ))}
                </select>
              </div>
              <div className="modal-footer">
                <button type="button" className="btn btn-secondary" onClick={() => setModalOpen(false)}>İptal</button>
                <button type="submit" className="btn btn-primary" disabled={saving || (!cizilen && !editBolge)}>
                  {saving ? 'Kaydediliyor...' : editBolge ? 'Güncelle' : 'Bölge Oluştur'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Leaflet Draw CSS ve JS */}
      <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/leaflet/1.9.4/leaflet.min.css" />
      <link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/leaflet.draw/1.0.4/leaflet.draw.css" />
    </Layout>
  );
}
